A debounce function delays invoking a callback until a specified wait time has passed since the last time it was called.

```javascript
// Debounce utility
function debounce(fn, delay) {
  let timer;
  return function (...args) {
    clearTimeout(timer);          // reset the timer on every call
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

// Example usage
const log = debounce((text) => console.log(text), 300);

// Suppose tied to an input’s “keyup” event:
log('a');   // ignored if next keystroke arrives within 300ms
log('ab');  // only this one will run 300ms after the last keystroke
```
